		return getReloadableResourceBundleMessageSource().getMessage(code, null, Locale.getDefault());
	}

	/**
	 * 정의된 메세지 조회
	 * @param code - 메세지 코드
	 * @param locale - 로케일
	 * @return String
	 */	
